from dataclasses import dataclass, field
from typing import Any


@dataclass
class Percept:
    state: Any
    reward: float  # from environment (fed through critic)


class PerformanceElement:
    """Current policy: maps state -> action."""

    def __init__(self):
        self.policy: dict[Any, str] = {}  # state -> action table

    def select_action(self, state: Any) -> str:
        return self.policy.get(state, "explore")

    def update(self, state: Any, action: str, value: float) -> None:
        self.policy[state] = action  # simplified: keep best


class Critic:
    """Evaluates outcomes against a fixed standard."""
    THRESHOLD = 0.7

    def evaluate(self, raw_reward: float) -> float:
        # Return normalised signal: positive = good, negative = bad
        return raw_reward - self.THRESHOLD


class LearningElement:
    """Updates the performance element from critic feedback."""

    def __init__(self, performance: PerformanceElement, critic: Critic):
        self.performance = performance
        self.critic = critic
        self.history: list[tuple] = []

    def learn(self, state: Any, action: str, raw_reward: float) -> None:
        signal = self.critic.evaluate(raw_reward)
        self.history.append((state, action, signal))
        # Update only when signal confirms a better action
        if signal > 0:
            self.performance.update(state, action, signal)


class ProblemGenerator:
    """Suggests exploratory actions not in the current policy."""

    def __init__(self, all_actions: list[str]):
        self.all_actions = all_actions

    def suggest(self, state: Any, policy: dict) -> str | None:
        known = policy.get(state)
        alternatives = [a for a in self.all_actions if a != known]
        import random
        return random.choice(alternatives) if alternatives else None


class LearningAgent:
    def __init__(self, actions: list[str]):
        self.performance = PerformanceElement()
        self.critic = Critic()
        self.learner = LearningElement(self.performance, self.critic)
        self.problem_gen = ProblemGenerator(actions)
        self.explore_rate = 0.3

    def act(self, state: Any) -> str:
        import random
        if random.random() < self.explore_rate:
            suggestion = self.problem_gen.suggest(state, self.performance.policy)
            return suggestion or self.performance.select_action(state)
        return self.performance.select_action(state)

    def receive_feedback(self, state: Any, action: str, reward: float) -> None:
        self.learner.learn(state, action, reward)

from dataclasses import dataclass


@dataclass
class PreferencePair:
    prompt: str
    chosen: str    # response humans preferred
    rejected: str  # response humans disliked


class RewardModel:
    """Trained to score responses; here simplified to keyword heuristic."""

    def score(self, prompt: str, response: str) -> float:
        positive = {"clear", "concise", "accurate", "helpful"}
        negative = {"wrong", "verbose", "hallucinated", "rude"}
        words = set(response.lower().split())
        return len(words & positive) - len(words & negative)


class RLHFCritic:
    """Critic backed by a reward model instead of a hard-coded threshold."""

    def __init__(self, reward_model: RewardModel):
        self.rm = reward_model

    def evaluate(self, prompt: str, response: str) -> float:
        return self.rm.score(prompt, response)


# Collect preferences
pairs = [
    PreferencePair("Summarise Python", "Python is a clear, concise language.", "Python verbose programming lang wrong"),
]
rm = RewardModel()
critic = RLHFCritic(rm)
print(critic.evaluate("Summarise Python", pairs[0].chosen))   # 2
print(critic.evaluate("Summarise Python", pairs[0].rejected))  # -2

from collections import deque
import random


class ExperienceReplay:
    """Stores past (state, action, reward, next_state) transitions."""

    def __init__(self, capacity: int = 1000):
        self.buffer: deque = deque(maxlen=capacity)

    def push(self, state, action: str, reward: float, next_state) -> None:
        self.buffer.append((state, action, reward, next_state))

    def sample(self, batch_size: int) -> list:
        return random.sample(self.buffer, min(batch_size, len(self.buffer)))

    def __len__(self) -> int:
        return len(self.buffer)


class DQNStyleLearner:
    """Q-learning with experience replay to reduce correlation between updates."""

    def __init__(self, actions: list[str], batch_size: int = 32):
        self.actions = actions
        self.replay = ExperienceReplay()
        self.q: dict[tuple, float] = {}
        self.alpha = 0.05
        self.gamma = 0.95
        self.batch_size = batch_size

    def _q(self, state, action) -> float:
        return self.q.get((state, action), 0.0)

    def push(self, state, action: str, reward: float, next_state) -> None:
        self.replay.push(state, action, reward, next_state)

    def train_step(self) -> None:
        if len(self.replay) < self.batch_size:
            return
        batch = self.replay.sample(self.batch_size)
        for state, action, reward, next_state in batch:
            best_next = max(self._q(next_state, a) for a in self.actions)
            target = reward + self.gamma * best_next
            self.q[(state, action)] += self.alpha * (target - self._q(state, action))


# Simulate 100 transitions, train after each batch
learner = DQNStyleLearner(["left", "right", "stay"])
for step in range(100):
    s = random.randint(0, 9)
    a = random.choice(["left", "right", "stay"])
    r = 1.0 if s == 5 else -0.1  # goal state = 5
    ns = max(0, min(9, s + {"left": -1, "right": 1, "stay": 0}[a]))
    learner.push(s, a, r, ns)
    learner.train_step()
print({a: learner._q(5, a) for a in ["left", "right", "stay"]})
